const Web3 = require('web3');
const { Wallet } = require('ethers');

// Configure the Ethereum node provider
const web3 = new Web3(new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'));

// Wallet configuration with private key (keep this secure and never expose in production code)
const privateKey = 'YOUR_PRIVATE_KEY';
const wallet = new Wallet(privateKey);

// Function to send ETH
async function sendEth(toAddress, amount) {
    const gasPrice = await web3.eth.getGasPrice();
    const transaction = {
        from: wallet.address,
        to: toAddress,
        value: web3.utils.toWei(amount.toString(), 'ether'),
        gas: 21000,
        gasPrice: gasPrice
    };

    const signedTransaction = await wallet.signTransaction(transaction);
    const receipt = await web3.eth.sendSignedTransaction(signedTransaction.rawTransaction);

    return receipt;
}

// Function to interact with a smart contract
async function callSmartContract(contractAddress, abi, methodName, params) {
    const contract = new web3.eth.Contract(abi, contractAddress);
    const gasPrice = await web3.eth.getGasPrice();

    // Example of calling a method that requires no transaction (view/pure)
    if (params.length === 0) {
        return await contract.methods[methodName]().call();
    }

    // Example of calling a method that requires a transaction
    const transaction = {
        from: wallet.address,
        to: contractAddress,
        gasPrice: gasPrice,
        data: contract.methods[methodName](...params).encodeABI()
    };

    const signedTransaction = await wallet.signTransaction(transaction);
    const receipt = await web3.eth.sendSignedTransaction(signedTransaction.rawTransaction);

    return receipt;
}

